  1	import * as React from 'react';
  2	import {
  3	  StorageSizeUnit,
  4	  StorageSizeUnitName,
  5	} from '@odf/shared/types/storage';
  6	import { Screen, render, screen } from '@testing-library/react';
  7	import userEvent from '@testing-library/user-event';
  8	import { CapacityAutoScaling } from './capacity-autoscaling';
  9	
 10	type WrapperProps = {
 11	  capacityLimit?: string;
 12	  enable?: boolean;
 13	  isEditView?: boolean;
 14	  osdAmount?: number;
 15	  osdSize?: string;
 16	};
 17	
 18	const Wrapper: React.FC<WrapperProps> = ({
 19	  capacityLimit: limit = '',
 20	  enable: enableFlag = false,
 21	  isEditView,
 22	  osdAmount = 3,
 23	  osdSize = `2${StorageSizeUnit.Ti}`,
 24	}) => {
 25	  const [enable, setEnable] = React.useState(enableFlag);
 26	  const [capacityLimit, setCapacityLimit] = React.useState<string>(limit);
 27	
 28	  const onChange = (_, checked) => {
 29	    setEnable(checked);
 30	  };
 31	
 32	  const onLimitSelect = (selected) => {
 33	    setCapacityLimit(selected);
 34	  };
 35	
 36	  return (
 37	    <CapacityAutoScaling
 38	      capacityLimit={capacityLimit}
 39	      enable={enable}
 40	      isEditView={isEditView}
 41	      onChange={onChange}
 42	      onLimitSelect={onLimitSelect}
 43	      osdAmount={osdAmount}
 44	      osdSize={osdSize}
 45	    />
 46	  );
 47	};
 48	
 49	const getCheckbox = (rtlScreen: Screen) =>
 50	  rtlScreen.getByRole<HTMLInputElement>('checkbox', {
 51	    name: /enable automatic capacity scaling for your cluster/i,
 52	  });
 53	const getAdditionalCostsAlert = (rtlScreen: Screen) =>
 54	  rtlScreen.queryByText(
 55	    /This may incur additional costs for the underlying storage./i
 56	  );
 57	const getAdditionalCostsLabel = (rtlScreen: Screen) =>
 58	  rtlScreen.queryByText(/^incur additional costs$/i);
 59	const getPopover = (rtlScreen: Screen) =>
 60	  rtlScreen.queryByRole('dialog', {
 61	    description:
 62	      /Automatic capacity scaling adds capacity through OSD expansion by resizing existing OSDs or adding new OSDs to maintain node balance./i,
 63	  });
 64	const getTypeaheadDropdown = (rtlScreen: Screen) =>
 65	  rtlScreen.queryByRole<HTMLInputElement>('combobox', {
 66	    name: /type to filter/i,
 67	  });
 68	
 69	describe('Capacity Autoscaling', () => {
 70	  it('shows disabled checkbox', () => {
 71	    render(<Wrapper />);
 72	
 73	    expect(getCheckbox(screen)).not.toBeChecked();
 74	    expect(getAdditionalCostsAlert(screen)).not.toBeInTheDocument();
 75	    expect(getAdditionalCostsLabel(screen)).not.toBeInTheDocument();
 76	    expect(getTypeaheadDropdown(screen)).not.toBeInTheDocument();
 77	  });
 78	
 79	  it('shows description popover on description link click', async () => {
 80	    const user = userEvent.setup();
 81	    render(<Wrapper />);
 82	
 83	    expect(getPopover(screen)).not.toBeInTheDocument();
 84	
 85	    const link = screen.getByRole('button', {
 86	      name: /how does it work?/i,
 87	    });
 88	    await user.click(link);
 89	
 90	    expect(getPopover(screen)).toBeVisible();
 91	  });
 92	
 93	  it('shows enabled checkbox (and required elements) on check', async () => {
 94	    const user = userEvent.setup();
 95	    render(<Wrapper />);
 96	
 97	    const checkbox = getCheckbox(screen);
 98	    await user.click(checkbox);
 99	
100	    expect(checkbox).toBeChecked();
101	    expect(getAdditionalCostsAlert(screen)).toBeVisible();
102	    expect(getAdditionalCostsLabel(screen)).not.toBeInTheDocument();
103	    expect(getTypeaheadDropdown(screen)).toBeVisible();
104	  });
105	
106	  it('does not preselect any limit when enabled', () => {
107	    render(<Wrapper enable={true} />);
108	
109	    expect(getTypeaheadDropdown(screen).value).toBeFalsy();
110	  });
111	
112	  it('shows the limit selected by the user', async () => {
113	    const user = userEvent.setup();
114	    render(<Wrapper enable={true} />);
115	
116	    const typeaheadDropdown = getTypeaheadDropdown(screen);
117	    await user.click(typeaheadDropdown);
118	
119	    const option = screen.getByRole('option', {
120	      name: /^12 tib/i,
121	    });
122	    await user.click(option);
123	
124	    expect(typeaheadDropdown.value).toBe(`12 ${StorageSizeUnitName.TiB}`);
125	  });
126	
127	  it('shows additional costs label on edit view', () => {
128	    render(<Wrapper isEditView />);
129	
130	    expect(getAdditionalCostsLabel(screen)).toBeVisible();
131	  });
132	});

